values.content:
=Extrae y normaliza el JSON del agente. Combina con estado previo si el agente omitió campos ya conocidos.

Salida del agente:
{{ $('AI Agent').item.json.output }}

Estado previo Redis:
{{ $('CONSULTAR ESTADO LEAD').item.json.lead_state || '{}' }}

Teléfono WhatsApp (usar si phone null): {{ $('Webhook').item.json.body.whatsappInboundMessage.from }}

parameters.jsCode:
const waFrom = $('Webhook').item.json.body.whatsappInboundMessage.from;

let prev = {};
try {
  const raw = $('CONSULTAR ESTADO LEAD').first().json.lead_state;
  if (raw) prev = JSON.parse(raw);
} catch {}

let model = $input.first().json.output?.[0]?.content?.[0]?.text ?? $input.first().json;
if (typeof model === 'string') {
  try { model = JSON.parse(model); } catch {}
}

function pick(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return null;
}

function digits(v) {
  if (!v) return null;
  const d = String(v).replace(/\D/g, '');
  return d || null;
}

const phone = digits(pick(model.phone, waFrom, prev.phone));

const merged = {
  reply_message: pick(model.reply_message, prev.reply_message) || 'Hola! Bienvenido a Miami Motors.',
  full_name: pick(model.full_name, prev.full_name),
  phone,
  city: pick(model.city, prev.city),
  payment_method: pick(model.payment_method, prev.payment_method),
  pie: model.pie != null && model.pie !== '' ? Number(model.pie) : (prev.pie != null ? Number(prev.pie) : null),
  purchase_time: pick(model.purchase_time, prev.purchase_time),
  budget: model.budget != null && model.budget !== '' ? Number(model.budget) : (prev.budget != null ? Number(prev.budget) : null),
  ready_for_sales: model.ready_for_sales === true || prev.ready_for_sales === true,
  route: pick(model.route, prev.route),
  lead_status: pick(model.lead_status, prev.lead_status),
  confidence_level: pick(model.confidence_level, prev.confidence_level),
  mensaje_mike: pick(model.mensaje_mike, prev.last_mensaje_mike) || '',
  mike_sent: prev.mike_sent === true,
  lead_id: prev.lead_id || null,
};

return [{ json: merged }];

parameters.jsonBody:
={{ (() => {
  const o = $('MERGE Y NORMALIZAR').item.json;
  const phone = $('Webhook').item.json.body.whatsappInboundMessage.from;
  const body = { source: 'whatsapp', update_existing: true, phone };
  if (o.full_name) body.full_name = o.full_name;
  if (o.city) body.region = o.city;
  if (o.payment_method) body.payment_type = o.payment_method;
  if (o.budget != null && !Number.isNaN(o.budget)) body.budget = String(o.budget);
  if (o.pie != null && !Number.isNaN(o.pie)) body.pie_disponible = String(o.pie);
  if (o.mensaje_mike) {
    body.mensaje_mike = o.mensaje_mike;
    body.chat_summary = o.mensaje_mike;
  }
  if (o.purchase_time) body.notes = 'Fecha estimada de compra: ' + o.purchase_time;
  if (o.ready_for_sales === true) body.status = 'interesado';
  return body;
})() }}

