const merged = $('MERGE Y NORMALIZAR').item.json;
const res = $input.first().json;
const api = res.body ?? res;
const leadId = api?.data?.id ?? merged.lead_id ?? null;

const state = {
  lead_id: leadId,
  mike_sent: merged.ready_for_sales ? true : merged.mike_sent,
  sent_at: merged.ready_for_sales && !merged.mike_sent ? new Date().toISOString() : null,
  full_name: merged.full_name,
  city: merged.city,
  payment_method: merged.payment_method,
  pie: merged.pie,
  purchase_time: merged.purchase_time,
  budget: merged.budget,
  ready_for_sales: merged.ready_for_sales,
  last_mensaje_mike: merged.mensaje_mike || '',
  last_route: merged.route || 'validacion',
  reply_message: merged.reply_message,
  phone: merged.phone,
};

return [{ json: { ...merged, lead_id: leadId, redis_payload: JSON.stringify(state) } }];
